#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmp);
        int threshold = a[N/2];
        int cnt = 0;
        for (int i = 0; i < N; ++i) if (a[i] >= threshold) ++cnt;
        printf("%d\n", cnt);
        free(a);
    }
    return 0;
}

