const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const arr = input.slice(idx, idx + N);
  idx += N;
  arr.sort((a, b) => a - b);
  const threshold = arr[Math.floor(N / 2)];
  // lower bound
  let lo = 0, hi = N;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid] < threshold) lo = mid + 1; else hi = mid;
  }
  const cnt = N - lo;
  outputs.push(String(cnt));
}
console.log(outputs.join('\n'));
